@@ -2,24 +2,50 @@ export function parseDuration(input: string, fallback: number): number {
   if (!input) {
     return fallback;
   }
-  const match = /^([0-9]+)(ms|s|m)?$/i.exec(input.trim());
-  if (!match) {
+  const trimmed = input.trim();
+  if (!trimmed) {
     return fallback;
   }
-  const value = Number(match[1]);
